changeSet.sql:
-- 1. MANUFACTURER CREATE TABLE manufacturer ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, name TEXT NOT NULL, country VARCHAR(3), reliability_rating DOUBLE PRECISION, version BIGINT, CONSTRAINT unique_name_constraint UNIQUE (name) );
-- 2. ENGINE CREATE TABLE engine ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, horsepower INTEGER NOT NULL, torque INTEGER NOT NULL, manufacturer_id BIGINT NOT NULL, motor_code VARCHAR(100), displacement INTEGER NOT NULL, engine_type VARCHAR(80) NOT NULL, fuel_type VARCHAR(50), version BIGINT, CONSTRAINT fk_engine_manufacturer FOREIGN KEY (manufacturer_id) REFERENCES manufacturer (id) );
-- 3. ELECTRIC_MOTOR CREATE TABLE electric_motor ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, horsepower INTEGER NOT NULL, torque INTEGER NOT NULL, manufacturer_id BIGINT NOT NULL, motor_code VARCHAR(100), battery_capacity INTEGER, battery_type BIGINT NOT NULL, version BIGINT, CONSTRAINT fk_electric_motor_manufacturer FOREIGN KEY (manufacturer_id) REFERENCES manufacturer (id), CONSTRAINT fk_electric_motor_battery_type FOREIGN KEY (battery_type) REFERENCES general_entries (id) );
-- 4. DRIVETRAIN CREATE TABLE drivetrain ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, engine_id BIGINT, electric_motor_id BIGINT, hybrid_type BIGINT, transmission_type BIGINT, number_of_gears INTEGER, version BIGINT, CONSTRAINT fk_drivetrain_engine FOREIGN KEY (engine_id) REFERENCES engine (id), CONSTRAINT fk_drivetrain_electric_motor FOREIGN KEY (electric_motor_id) REFERENCES electric_motor (id), CONSTRAINT fk_drivetrain_hybrid_type FOREIGN KEY (hybrid_type) REFERENCES general_entries (id), CONSTRAINT fk_drivetrain_transmission_type FOREIGN KEY (transmission_type) REFERENCES general_entries (id) );
-- 5. CAR_MODEL CREATE TABLE car_model ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, car_name TEXT NOT NULL, model_year INTEGER NOT NULL, generation INTEGER NOT NULL, facelift INTEGER, manufacturer_id BIGINT NOT NULL, internal_code VARCHAR(50), doors INTEGER NOT NULL, version BIGINT, CONSTRAINT fk_car_model_manufacturer FOREIGN KEY (manufacturer_id) REFERENCES manufacturer (id) );
-- 6. CAR_SPECIFICATIONS CREATE TABLE car_specifications ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, car_id BIGINT NOT NULL, drivetrain_id BIGINT NOT NULL, version BIGINT, CONSTRAINT fk_car_spec_car FOREIGN KEY (car_id) REFERENCES car_model (id), CONSTRAINT fk_car_spec_drivetrain FOREIGN KEY (drivetrain_id) REFERENCES drivetrain (id) );
-- 7. TECHNICAL_DETAILS CREATE TABLE technical_details ( car_id BIGINT PRIMARY KEY, zero_to_one_hundred NUMERIC(4, 2), top_speed INTEGER, city_consumption NUMERIC(4, 2), highway_consumption NUMERIC(4, 2), electric_range INTEGER, weight INTEGER NOT NULL, wheels_driven VARCHAR(3), drivetrain_place VARCHAR(30), total_horsepower INTEGER NOT NULL, CONSTRAINT fk_tech_details_car_spec FOREIGN KEY (car_id) REFERENCES car_specifications (id) ON DELETE CASCADE );

changeSet.rollback:
DROP TABLE technical_details;
DROP TABLE car_specifications;
DROP TABLE car_model;
DROP TABLE drivetrain;
DROP TABLE electric_motor;
DROP TABLE engine;
DROP TABLE manufacturer;
